defaultModel:
{{
  (function() {
    // ⚠️ REPLACE "YOUR_QUERY_NAME" WITH THE ACTUAL NAME OF YOUR S3 QUERY ⚠️
    const incomingData = RedTeam_Query.data; 

    if (!incomingData) return { "red_team_data": {} };

    // Case 1: Appsmith automatically parsed the JSON directly from S3
    if (typeof incomingData === 'object' && incomingData.metadata) {
      return { "red_team_data": incomingData };
    }

    // Case 2: The JSON is wrapped inside 'fileData' or 'body' (common for S3 plugins)
    let textData = incomingData.fileData || incomingData.body || incomingData;

    try {
      // Attempt base64 decode just in case Appsmith encoded the string
      try { textData = atob(textData); } catch(e) {}

      return { 
        "red_team_data": typeof textData === 'string' ? JSON.parse(textData) : textData 
      };
    } catch (e) {
      return { "red_team_data": {} };
    }
  })()
}}
